import { isNetworkVisualConfig, normalizeNetworkVisualConfig, validateNetworkVisualConfig } from '../../content/network-visual.mjs';
import { supportedBlockTypes, blockTypeOptionsForContext } from '../../content/block-registry.mjs';
function blockKind(type) { return supportedBlockTypes.has(type) ? type : String(type || 'text'); }
function editorMode(type) { if (['feature-list','list'].includes(type)) return 'feature-list'; if (['cards','card-grid'].includes(type)) return 'cards'; if (type === 'ai-preview') return 'ai-preview'; if (type === 'network-visual') return 'network-visual'; if (type === 'split-text') return 'split-text'; if (type === 'ai-assistant-preview') return 'ai-assistant-preview'; if (type === 'integrations-strip') return 'integrations-strip'; if (!supportedBlockTypes.has(type)) return 'raw'; return type; }
const asObj = (it) => typeof it === 'object' && it ? it : { title: it || '' };
const titleOf = (it) => typeof it === 'string' ? it : (it.title || it.text || it.question || it.heading || it.label || '');
const textOf = (it) => typeof it === 'object' && it ? (it.text || it.shortDescription || it.answer || it.body || '') : '';
const urlOf = (it) => typeof it === 'object' && it ? (it.url || it.href || it.slug || it.id || it.kind || it.role || '') : '';
const labelOf = (it) => typeof it === 'object' && it ? (it.linkLabel || it.label || '') : '';
const targetTypeOf = (it) => ['page','legacy','external'].includes(String(it?.target_type || '')) ? String(it.target_type) : (it?.target_page_id ? 'page' : (String(it?.href || it?.url || '').startsWith('http') ? 'external' : 'legacy'));
function pageTargetOptions(pages = [], selected = '') { return (pages || []).filter((page)=>page.status === 'published' && page.route !== '/' && page.type !== 'home').map((page)=>`<option value="${esc(page.id)}" ${String(selected)===String(page.id)?'selected':''}>${esc(page.title || ('#'+page.id))} — ${esc(page.route || '')}${page.type ? ' — '+esc(page.type) : ''}</option>`).join(''); }
function cardTargetEditor(it = {}, pages = []) { const t = targetTypeOf(it); return `<label data-field="card-target-type">Cél típusa<select data-card-target-type><option value="page" ${t==='page'?'selected':''}>Belső oldal</option><option value="legacy" ${t==='legacy'?'selected':''}>Belső URL</option><option value="external" ${t==='external'?'selected':''}>Külső URL</option></select></label><label data-field="card-target-page">Belső oldal<select data-card-target-page>${pageTargetOptions(pages, it.target_page_id || '')}</select></label><label data-field="card-target-href">URL<input data-card-target-href value="${esc(it.href || it.url || '')}"></label>`; }
function cardsActionEditor(items = [], pages = []) { const cfg = items?.[0]?.version === 2 ? items[0] : {}; const action = cfg.action || (items || []).find((it)=>it?.kind==='section-action') || {}; const enabled = Boolean(action.label || action.title_override || action.href || action.target_page_id); const t = targetTypeOf(action); return `<div data-cards-action-editor><h4>Szekcióvégi gomb</h4><label><input type="checkbox" data-cards-action-enabled ${enabled?'checked':''}> Gomb megjelenítése</label><label>Felirat<input data-cards-action-label value="${esc(action.label || action.title_override || action.title || '')}"></label><label>Cél típusa<select data-cards-action-target-type><option value="page" ${t==='page'?'selected':''}>Belső oldal</option><option value="legacy" ${t==='legacy'?'selected':''}>Belső URL</option><option value="external" ${t==='external'?'selected':''}>Külső URL</option></select></label><label>Belső oldal<select data-cards-action-page>${pageTargetOptions(pages, action.target_page_id || '')}</select></label><label>URL<input data-cards-action-href value="${esc(action.href || action.url || '')}"></label></div>`; }
const panelClasses = ' class="is-runtime-hidden" hidden inert';

const aiPreviewKindOptions = [['risk','Kockázat'],['metric','Mérőszám'],['opportunity','Lehetőség'],['recommendation','Javaslat'],['success','Siker'],['info','Információ']];
const aiPreviewKind = (it) => aiPreviewKindOptions.some(([value]) => value === it?.kind) ? it.kind : 'info';
const aiPreviewTitle = (it) => typeof it === 'string' ? it : (it?.title || it?.text || it?.label || '');
function aiPreviewRows(items) { const list = items.length ? items : [{ kind: 'info', title: '' }]; return list.map((raw) => { const it = asObj(raw); return `<div class="item-row ai-preview-row" data-item-row data-raw-item="${esc(JSON.stringify(raw))}"><label data-field="ai-kind">Típus / kind<select data-ai-kind>${aiPreviewKindOptions.map(([value,label]) => `<option value="${value}" ${aiPreviewKind(it)===value?'selected':''}>${label}</option>`).join('')}</select></label><label data-field="ai-title">Fő üzenet / title<input data-ai-title value="${esc(aiPreviewTitle(raw))}"></label><label data-field="ai-detail">Részletezés / detail<input data-ai-detail value="${esc(it.detail || '')}"></label><label data-field="ai-value">Kiemelt érték / value<input data-ai-value value="${esc(it.value || '')}"></label><label data-field="ai-href">Opcionális link / href<input data-ai-href value="${esc(it.href || it.url || '')}"></label><label data-field="ai-order">Sorrend / order<input data-ai-order value="${esc(it.order || '')}"></label><button type="button" data-move-item="up" class="secondary">Fel</button><button type="button" data-move-item="down" class="secondary">Le</button><button type="button" data-duplicate-item class="secondary">Duplikálás</button><button type="button" data-remove-item class="danger">Törlés</button></div>`; }).join(''); }

const networkKinds = [['core','Központi'],['module','Modul'],['external','Külső rendszer'],['data-source','Adatforrás'],['ai','AI'],['user','Felhasználó']];
const networkDirections = [['none','Nincs'],['forward','Egyirányú'],['backward','Visszafelé'],['both','Kétirányú']];
function networkConfigFromItems(items) { return isNetworkVisualConfig(items?.[0]) ? normalizeNetworkVisualConfig(items[0]) : { version: 1, layout: 'hub', showLegend: true, nodes: [], edges: [] }; }
function networkNodeRows(cfg) { return (cfg.nodes.length ? cfg.nodes : [{ id: 'easylink', label: 'EasyLink ERP', kind: 'core' }]).map((n) => `<div class="item-row network-node-row" data-network-node><label>ID<input data-network-node-id value="${esc(n.id || '')}"></label><label>Név / label<input data-network-node-label value="${esc(n.label || '')}"></label><label>Leírás<input data-network-node-description value="${esc(n.description || '')}"></label><label>Típus<select data-network-node-kind>${networkKinds.map(([v,l])=>`<option value="${v}" ${n.kind===v?'selected':''}>${l}</option>`).join('')}</select></label><label>Link / href<input data-network-node-href value="${esc(n.href || n.url || '')}"></label><label>Sorrend<input data-network-node-order value="${esc(n.order || '')}"></label><button type="button" data-move-network-node="up" class="secondary">Fel</button><button type="button" data-move-network-node="down" class="secondary">Le</button><button type="button" data-duplicate-network-node class="secondary">Duplikálás</button><button type="button" data-remove-network-node class="danger">Törlés</button></div>`).join(''); }
function networkEdgeRows(cfg) { const opts = cfg.nodes.map((n)=>`<option value="${esc(n.id)}">${esc(n.label || n.id)}</option>`).join(''); return cfg.edges.map((e) => { const fromOpts = opts.replace(`value="${esc(e.from)}"`, `value="${esc(e.from)}" selected`); const toOpts = opts.replace(`value="${esc(e.to)}"`, `value="${esc(e.to)}" selected`); return `<div class="item-row network-edge-row" data-network-edge><label>From<select data-network-edge-from>${fromOpts}</select></label><label>To<select data-network-edge-to>${toOpts}</select></label><label>Irány<select data-network-edge-direction>${networkDirections.map(([v,l])=>`<option value="${v}" ${e.direction===v?'selected':''}>${l}</option>`).join('')}</select></label><label>Címke<input data-network-edge-label value="${esc(e.label || '')}"></label><button type="button" data-remove-network-edge class="danger">Törlés</button></div>`; }).join(''); }
function networkPanel(items, selectedKind) { if (selectedKind !== 'network-visual') return ''; const cfg = networkConfigFromItems(items); const legacy = !isNetworkVisualConfig(items?.[0]) && items.length; return `<div data-panel="network-visual" data-network-visual-editor><p class="hint">${legacy ? 'Régi listás formátum – az adat nem konvertálódik automatikusan.' : 'Strukturált node/edge hálózati vizualizáció.'}</p><label>Layout<select data-network-layout><option value="hub" ${cfg.layout!=='flow'?'selected':''}>hub / központi</option><option value="flow" ${cfg.layout==='flow'?'selected':''}>flow / folyamat</option></select></label><label><input type="checkbox" data-network-show-legend ${cfg.showLegend!==false?'checked':''}> Jelmagyarázat</label><h4>Csomópontok</h4><div data-network-nodes>${networkNodeRows(cfg)}</div><button type="button" data-add-network-node>Új node</button><h4>Kapcsolatok</h4><div data-network-edges>${networkEdgeRows(cfg)}</div><button type="button" data-add-network-edge>Új kapcsolat</button><p class="msg err is-runtime-hidden" data-network-error hidden></p></div><details data-panel="network-visual-raw"><summary>Haladó JSON export</summary><textarea data-network-json readonly>${esc(JSON.stringify(items, null, 2))}</textarea></details>`; }

function aiPreviewPanel(items, selectedKind) { if (selectedKind !== 'ai-preview') return ''; return `<div data-panel="ai-preview" data-ai-preview-editor><p class="hint">AI üzleti pillanatkép demo elemei. A tartalom kézzel szerkeszthető bemutató, nem élő AI-futtatás.</p>${aiPreviewRows(items)}<button type="button" data-add-ai-item>Új AI elem</button></div><details data-panel="ai-preview-raw"><summary>Haladó JSON export / fallback</summary><textarea data-ai-preview-json-export readonly>${esc(JSON.stringify(items, null, 2))}</textarea></details>`; }

function itemFieldShown(mode, field) { return (mode === 'feature-list' && field === 'item-title') || (mode === 'cards' && ['item-title','item-text','item-label','item-badge'].includes(field)) || (mode === 'faq' && ['item-title','item-text'].includes(field)); }
function fieldAttrs(mode, field) { return itemFieldShown(mode, field) ? '' : ' class="is-runtime-hidden" hidden'; }
function fieldDisabledAttrs(mode, field) { return itemFieldShown(mode, field) ? '' : ' disabled'; }
function itemRows(items, mode, pages = []) { const sourceItems = mode === 'cards' && items?.[0]?.version === 2 ? (items[0].cards || []) : items; const list = sourceItems.length ? sourceItems : ['']; return list.map((raw) => { const it = asObj(raw); const rawItem = esc(JSON.stringify(raw)); return `<div class="item-row" data-item-row data-raw-item="${rawItem}"><label data-field="item-title"${fieldAttrs(mode, 'item-title')}>${mode === 'faq' ? 'Kérdés' : mode === 'cards' ? 'Kártya címe' : mode === 'split-text' ? 'Heading' : mode === 'integrations-strip' ? 'Integration label' : mode === 'ai-assistant-preview' ? 'Elem címe' : 'Listaelem'}<input data-item-title value="${esc(titleOf(raw))}"${fieldDisabledAttrs(mode, 'item-title')}></label>${itemFieldShown(mode, 'item-text') ? `<label data-field="item-text">${mode === 'faq' ? 'Válasz' : mode === 'ai-assistant-preview' ? 'Üzenet szöveg' : 'Kártya szövege'}<input data-item-text value="${esc(textOf(raw))}"></label>` : ''}${itemFieldShown(mode, 'item-url') ? `<label data-field="item-url">${mode === 'integrations-strip' ? 'Integration ID' : mode === 'ai-assistant-preview' ? 'Kind/role' : 'Cél URL / slug'}<input data-item-url value="${esc(urlOf(raw))}"></label>` : ''}${itemFieldShown(mode, 'item-label') ? `<label data-field="item-label">Link felirat<input data-item-label placeholder="Részletek →" value="${esc(labelOf(raw))}"></label>` : ''}${itemFieldShown(mode, 'item-badge') ? `<label data-field="item-badge">Sorrend / badge<input data-item-badge value="${esc(it.order || it.badge || '')}"></label>` : ''}${mode === 'cards' ? cardTargetEditor(it, pages) : ''}<button type="button" data-move-item="up" class="secondary">Fel</button><button type="button" data-move-item="down" class="secondary">Le</button><button type="button" data-remove-item class="danger">Törlés</button></div>`; }).join(''); }
function rawItemsPanel(items, selectedKind) { if (selectedKind === 'network-visual') return `<label data-panel="raw-items" class="is-runtime-hidden" hidden inert>Items JSON<textarea data-raw-items disabled>${esc(JSON.stringify(items, null, 2))}</textarea><span class="msg err is-runtime-hidden" data-raw-error hidden>Az items JSON hibás. Javítsd mentés előtt.</span></label>`; if (selectedKind !== 'raw') return ''; return `<label data-panel="raw-items">Items JSON<textarea data-raw-items>${esc(JSON.stringify(items, null, 2))}</textarea><span class="msg err is-runtime-hidden" data-raw-error hidden>Az items JSON hibás. Javítsd mentés előtt.</span></label>`; }

function splitTextPanel(items, selectedKind) { if (selectedKind !== 'split-text') return ''; const first = asObj(items[0] || {}); return `<div data-panel="split-text" data-split-text-editor><label>Heading<input data-split-heading value="${esc(first.heading || first.text || '')}"></label><label>Layout<select data-split-layout><option value="split" ${(first.layout || 'split') === 'split' ? 'selected' : ''}>split</option></select></label></div>`; }
function aiAssistantPanel(items, selectedKind) { if (selectedKind !== 'ai-assistant-preview') return ''; const heading = (items || []).find((i)=>i?.kind==='heading')?.text || ''; const sources = (items || []).filter((i)=>i?.kind==='source'); const messages = (items || []).filter((i)=>i?.kind==='message'); return `<div data-panel="ai-assistant-preview" data-ai-assistant-editor><label>Heading<input data-ai-assistant-heading value="${esc(heading)}"></label><h4>Sources</h4><div data-ai-assistant-sources>${(sources.length?sources:[{title:''}]).map((source)=>`<div class="item-row" data-ai-source-row><label>Source title<input data-ai-source-title value="${esc(source.title || '')}"></label><button type="button" data-move-ai-source="up" class="secondary">Fel</button><button type="button" data-move-ai-source="down" class="secondary">Le</button><button type="button" data-remove-ai-source class="danger">Törlés</button></div>`).join('')}</div><button type="button" data-add-ai-source>Új source</button><h4>Messages</h4><div data-ai-assistant-messages>${(messages.length?messages:[{role:'assistant',title:'',text:''}]).map((message)=>`<div class="item-row" data-ai-message-row><label>Role<select data-ai-message-role><option value="user" ${message.role==='user'?'selected':''}>user</option><option value="assistant" ${message.role!=='user'?'selected':''}>assistant</option></select></label><label>Title<input data-ai-message-title value="${esc(message.title || '')}"></label><label>Text<input data-ai-message-text value="${esc(message.text || '')}"></label><button type="button" data-move-ai-message="up" class="secondary">Fel</button><button type="button" data-move-ai-message="down" class="secondary">Le</button><button type="button" data-remove-ai-message class="danger">Törlés</button></div>`).join('')}</div><button type="button" data-add-ai-message>Új message</button></div>`; }
function integrationsStripPanel(items, selectedKind) { if (selectedKind !== 'integrations-strip') return ''; const heading = (items || []).find((i)=>i?.kind==='heading')?.text || ''; const nodes = (items || []).filter((i)=>i?.kind==='node'); return `<div data-panel="integrations-strip" data-integrations-strip-editor><label>Heading<input data-integrations-heading value="${esc(heading)}"></label><h4>Integrations</h4><div data-integration-nodes>${(nodes.length?nodes:[{id:'',label:''}]).map((node)=>`<div class="item-row" data-integration-row><label>ID<input data-integration-id value="${esc(node.id || '')}"></label><label>Label<input data-integration-label value="${esc(node.label || node.title || '')}"></label><button type="button" data-move-integration="up" class="secondary">Fel</button><button type="button" data-move-integration="down" class="secondary">Le</button><button type="button" data-remove-integration class="danger">Törlés</button></div>`).join('')}</div><button type="button" data-add-integration>Új integration</button></div>`; }

function itemsPanel(items, selectedKind, pages = []) { if (!['feature-list','cards','faq'].includes(selectedKind)) return ''; return `<div data-panel="items" data-list-editor><p class="hint" data-kind-hint></p>${itemRows(items, selectedKind, pages)}<button type="button" data-add-item>Új sor</button>${selectedKind === 'cards' ? cardsActionEditor(items, pages) : ''}</div>`; }
function ctaPanel(first, selectedKind, { pageCtaEditor = false, defaultCta = {}, title = '', body = '' } = {}) { if (selectedKind !== 'cta') return ''; if (!pageCtaEditor) return `<div class="grid" data-panel="cta"><label>Kis címke / eyebrow<input data-cta-eyebrow value="${esc(first.eyebrow || '')}"></label><label>Első gomb felirat<input data-cta-label value="${esc(first.label || '')}"></label><label>Első gomb link<input data-cta-url value="${esc(first.url || '')}"></label><label>Második gomb felirat<input data-cta-secondary-label value="${esc(first.secondaryLabel || '')}"></label><label>Második gomb link<input data-cta-secondary-url value="${esc(first.secondaryUrl || '')}"></label></div>`; const mode = ['global','custom','hidden'].includes(String(first.ctaMode || '')) ? String(first.ctaMode) : 'global'; const checked = (v) => mode === v ? ' checked' : ''; return `<div class="grid" data-panel="cta" data-page-cta-editor data-default-cta='${esc(JSON.stringify(defaultCta || {}))}'><fieldset><legend>CTA megjelenési mód</legend><label><input type="radio" name="ctaModeChoice" value="global" data-cta-mode${checked('global')}> Globális CTA használata</label><label><input type="radio" name="ctaModeChoice" value="custom" data-cta-mode${checked('custom')}> Egyedi CTA használata</label><label><input type="radio" name="ctaModeChoice" value="hidden" data-cta-mode${checked('hidden')}> CTA kikapcsolása ezen az oldalon</label></fieldset><div data-cta-global-preview><p class="hint">Ez az oldal az Alapadatokban megadott globális CTA-t használja.</p><p><strong>${esc(defaultCta.eyebrow || '')}</strong></p><p>${esc(defaultCta.title || '')}</p><p>${esc(defaultCta.description || '')}</p><p>${esc(defaultCta.primaryLabel || '')} → ${esc(defaultCta.primaryUrl || '')}</p><p>${esc(defaultCta.secondaryLabel || '')} → ${esc(defaultCta.secondaryUrl || '')}</p></div><div data-cta-hidden-warning><p class="hint">Ezen az oldalon nem jelenik meg oldalvégi CTA.</p></div><div data-cta-local-fields><label>Kis címke / eyebrow<input data-cta-eyebrow value="${esc(first.eyebrow || '')}"></label><label>Főcím<input data-page-cta-title value="${esc(title || '')}"></label><label>Leírás<textarea data-page-cta-body>${esc(body || '')}</textarea></label><label>Első gomb felirat<input data-cta-label value="${esc(first.label || '')}"></label><label>Első gomb link<input data-cta-url value="${esc(first.url || '')}"></label><label>Második gomb felirat<input data-cta-secondary-label value="${esc(first.secondaryLabel || '')}"></label><label>Második gomb link<input data-cta-secondary-url value="${esc(first.secondaryUrl || '')}"></label></div></div>`; }
function imagePanel(first, selectedKind) { if (selectedKind !== 'image-text') return ''; return `<div class="grid" data-panel="image-text"><label>Kép URL<input data-image-url value="${esc(first.image || '')}"></label><button type="button" class="secondary" data-media-picker-target="[data-image-url]" data-media-picker-kind="image">Médiából választok</button><label>Alt text<input data-image-alt value="${esc(first.alt || '')}"></label><label>Kép pozíció<select data-image-position><option value="right" ${first.position!=='left'?'selected':''}>jobb</option><option value="left" ${first.position==='left'?'selected':''}>bal</option></select></label></div>`; }
function videoPanel(first, selectedKind) { if (selectedKind !== 'video') return ''; const cfg = first && typeof first === 'object' ? first : {}; const checked = (v) => v ? ' checked' : ''; const mutedDefault = cfg.muted ?? true; const controlsDefault = cfg.autoplay === false ? true : cfg.controls !== false; return `<section class="grid" data-panel="video"><label>Forrás típusa<select data-video-source><option value="media" ${cfg.sourceType !== 'youtube' ? 'selected' : ''}>Saját MP4</option><option value="youtube" ${cfg.sourceType === 'youtube' ? 'selected' : ''}>YouTube</option></select></label><label data-video-media>Saját videó<input data-video-media-path value="${esc(cfg.mediaPath || '')}"></label><button type="button" class="secondary" data-video-media data-media-picker-target="[data-video-media-path]" data-media-picker-kind="video">Videót választok</button><label data-video-youtube>YouTube link<input data-video-youtube-url value="${esc(cfg.youtubeUrl || '')}"></label><label>Poster / fallback kép<input data-video-poster value="${esc(cfg.poster || '')}"></label><button type="button" class="secondary" data-media-picker-target="[data-video-poster]" data-media-picker-kind="image">Képet választok</button><label><input type="checkbox" data-video-autoplay${checked(cfg.autoplay)}> Automatikus indítás</label><label><input type="checkbox" data-video-muted${checked(mutedDefault)}> Némítva</label><label><input type="checkbox" data-video-loop${checked(cfg.loop)}> Végtelenített lejátszás</label><label><input type="checkbox" data-video-controls${checked(controlsDefault)}${cfg.autoplay === false ? ' disabled aria-disabled="true"' : ''}> Vezérlők megjelenítése</label><label>Előtöltés<select data-video-preload><option value="none" ${cfg.preload === 'none' ? 'selected' : ''}>Nincs</option><option value="metadata" ${!cfg.preload || cfg.preload === 'metadata' ? 'selected' : ''}>Metaadat</option><option value="auto" ${cfg.preload === 'auto' ? 'selected' : ''}>Automatikus</option></select></label><label>Illesztés<select data-video-object-fit><option value="cover" ${cfg.objectFit !== 'contain' ? 'selected' : ''}>Kitöltés, vágással</option><option value="contain" ${cfg.objectFit === 'contain' ? 'selected' : ''}>Teljes videó látszódjon</option></select></label><label>Képarány<select data-video-aspect-ratio><option value="auto" ${cfg.aspectRatio === 'auto' ? 'selected' : ''}>Automatikus</option><option value="16/9" ${!cfg.aspectRatio || cfg.aspectRatio === '16/9' ? 'selected' : ''}>16:9</option><option value="4/3" ${cfg.aspectRatio === '4/3' ? 'selected' : ''}>4:3</option><option value="1/1" ${cfg.aspectRatio === '1/1' ? 'selected' : ''}>1:1</option><option value="9/16" ${cfg.aspectRatio === '9/16' ? 'selected' : ''}>9:16</option></select></label></section>`; }


export function videoPanelVisibility(sourceType = 'media') {
  const source = sourceType === 'youtube' ? 'youtube' : 'media';
  return { sourceType: source, mediaVisible: source === 'media', youtubeVisible: source === 'youtube' };
}

export function serializeVideoEditorValues(values = {}) {
  const sourceType = values.sourceType === 'youtube' ? 'youtube' : 'media';
  const autoplay = Boolean(values.autoplay);
  const cfg = {
    sourceType,
    autoplay,
    muted: Boolean(values.muted),
    loop: Boolean(values.loop),
    controls: autoplay ? values.controls !== false : true,
    preload: values.preload || 'metadata',
    objectFit: values.objectFit || 'cover',
    aspectRatio: values.aspectRatio || '16/9',
  };
  if (sourceType === 'media') cfg.mediaPath = values.mediaPath || '';
  else cfg.youtubeUrl = values.youtubeUrl || '';
  if (values.poster) cfg.poster = values.poster;
  return cfg;
}

export function setVideoEditorVisible(el, show, hiddenClass = 'is-runtime-hidden') {
  if (!el) return;
  el.hidden = !show;
  el.classList?.toggle?.(hiddenClass, !show);
  if (show) el.removeAttribute?.('inert');
  else el.setAttribute?.('inert', '');
  el.querySelectorAll?.('input,textarea,select,button').forEach((input) => { input.disabled = !show; });
}

export function ensureVideoPanel(form, beforeElement = null, deps = {}) {
  let panel = form?.querySelector?.('[data-panel="video"]');
  if (panel) return panel;
  const before = beforeElement || form?.querySelector?.('input[name="items"]');
  if (!before?.insertAdjacentHTML) return null;
  const hiddenClass = deps.runtimeHiddenClass || 'is-runtime-hidden';
  before.insertAdjacentHTML('beforebegin', `<section class="grid ${hiddenClass}" data-panel="video" hidden inert><label>Forrás típusa<select data-video-source disabled><option value="media">Saját MP4</option><option value="youtube">YouTube</option></select></label><label data-video-media>Saját videó<input data-video-media-path disabled></label><button type="button" class="secondary" data-video-media data-media-picker-target="[data-video-media-path]" data-media-picker-kind="video" disabled>Videót választok</button><label data-video-youtube>YouTube link<input data-video-youtube-url disabled></label><label>Poster / fallback kép<input data-video-poster disabled></label><button type="button" class="secondary" data-media-picker-target="[data-video-poster]" data-media-picker-kind="image" disabled>Képet választok</button><label><input type="checkbox" data-video-autoplay disabled> Automatikus indítás</label><label><input type="checkbox" data-video-muted checked disabled> Némítva</label><label><input type="checkbox" data-video-loop disabled> Végtelenített lejátszás</label><label><input type="checkbox" data-video-controls checked disabled aria-disabled="true"> Vezérlők megjelenítése</label><label>Előtöltés<select data-video-preload disabled><option value="none">Nincs</option><option value="metadata" selected>Metaadat</option><option value="auto">Automatikus</option></select></label><label>Illesztés<select data-video-object-fit disabled><option value="cover">Kitöltés, vágással</option><option value="contain">Teljes videó látszódjon</option></select></label><label>Képarány<select data-video-aspect-ratio disabled><option value="auto">Automatikus</option><option value="16/9" selected>16:9</option><option value="4/3">4:3</option><option value="1/1">1:1</option><option value="9/16">9:16</option></select></label></section>`);
  return form.querySelector('[data-panel="video"]');
}

export function syncVideoSource(form, setVisibleFn = setVideoEditorVisible) {
  const visibility = videoPanelVisibility(form?.querySelector?.('[data-video-source]')?.value || 'media');
  form?.querySelectorAll?.('[data-video-media]').forEach((el) => setVisibleFn(el, visibility.mediaVisible));
  form?.querySelectorAll?.('[data-video-youtube]').forEach((el) => setVisibleFn(el, visibility.youtubeVisible));
  return visibility;
}

export function syncVideoUiState(form, setVisibleFn = setVideoEditorVisible) {
  const visibility = syncVideoSource(form, setVisibleFn);
  const autoplay = !!form?.querySelector?.('[data-video-autoplay]')?.checked;
  const muted = form?.querySelector?.('[data-video-muted]');
  const controls = form?.querySelector?.('[data-video-controls]');
  if (controls) {
    if (!autoplay) controls.checked = true;
    controls.disabled = !autoplay;
    controls.setAttribute?.('aria-disabled', !autoplay ? 'true' : 'false');
  }
  return visibility;
}

export function readVideoEditorValues(form) {
  const sourceType = form?.querySelector?.('[data-video-source]')?.value === 'youtube' ? 'youtube' : 'media';
  const values = {
    sourceType,
    poster: form?.querySelector?.('[data-video-poster]')?.value || '',
    autoplay: !!form?.querySelector?.('[data-video-autoplay]')?.checked,
    muted: !!form?.querySelector?.('[data-video-muted]')?.checked,
    loop: !!form?.querySelector?.('[data-video-loop]')?.checked,
    controls: !form?.querySelector?.('[data-video-autoplay]')?.checked ? true : !!form?.querySelector?.('[data-video-controls]')?.checked,
    preload: form?.querySelector?.('[data-video-preload]')?.value || 'metadata',
    objectFit: form?.querySelector?.('[data-video-object-fit]')?.value || 'cover',
    aspectRatio: form?.querySelector?.('[data-video-aspect-ratio]')?.value || '16/9',
  };
  if (sourceType === 'media') values.mediaPath = form?.querySelector?.('[data-video-media-path]')?.value || '';
  else values.youtubeUrl = form?.querySelector?.('[data-video-youtube-url]')?.value || '';
  return values;
}

export function hydrateVideoPanel(form, config = {}, setVisibleFn = setVideoEditorVisible) {
  const first = config && typeof config === 'object' && !Array.isArray(config) ? config : {};
  const set = (sel, val) => { const el = form?.querySelector?.(sel); if (el && val !== undefined && val !== null) el.value = val; };
  const source = first.sourceType === 'youtube' ? 'youtube' : 'media';
  set('[data-video-source]', source);
  set('[data-video-media-path]', first.mediaPath || '');
  set('[data-video-youtube-url]', first.youtubeUrl || '');
  set('[data-video-poster]', first.poster || '');
  ['autoplay','muted','loop','controls'].forEach((key) => {
    const el = form?.querySelector?.(`[data-video-${key}]`);
    if (el) el.checked = key === 'controls' ? first[key] !== false : !!first[key];
  });
  set('[data-video-preload]', first.preload || 'metadata');
  set('[data-video-object-fit]', first.objectFit || 'cover');
  set('[data-video-aspect-ratio]', first.aspectRatio || '16/9');
  return syncVideoUiState(form, setVisibleFn);
}

export function writeVideoItemsInput(form) {
  const cfg = serializeVideoEditorValues(readVideoEditorValues(form));
  const input = form?.querySelector?.('input[name="items"]');
  if (input) input.value = JSON.stringify([cfg]);
  return [cfg];
}

export function parseItemRowRaw(rawItem = '{}') { return JSON.parse(rawItem || '{}'); }

export function serializeEditorItems({ type, rows = [], first = {}, rawItemsText = '[]' } = {}) {
  const setClean = (obj, key, value) => { if (value === '' || value === undefined || value === null) delete obj[key]; else obj[key] = value; };
  const objectRaw = (raw) => raw && typeof raw === 'object' && !Array.isArray(raw) ? { ...raw } : {};
  const coerceOrder = (key, value, fallback) => {
    if (value === '' || value === undefined || value === null) return fallback;
    if (key === 'badge') return value;
    const numeric = Number(value);
    return Number.isFinite(numeric) ? numeric : value;
  };
  if (type === 'feature-list') return rows.map((i) => {
    const raw = objectRaw(i.raw);
    if (Object.keys(raw).length) {
      const textKey = ('text' in raw && !('title' in raw)) ? 'text' : 'title';
      setClean(raw, textKey, i.title);
      return raw;
    }
    return i.title;
  }).filter((i) => typeof i === 'string' ? Boolean(i) : Boolean(i?.title || i?.text));
  if (type === 'split-text') return [{ version: 1, heading: rows.heading || '', layout: rows.layout || 'split' }];
  if (type === 'ai-assistant-preview') { const out=[{ kind: 'heading', text: rows.heading || '' }]; for (const source of rows.sources || []) if (source.title) out.push({ kind: 'source', title: source.title }); for (const message of rows.messages || []) if (message.title || message.text) out.push({ kind: 'message', role: message.role === 'user' ? 'user' : 'assistant', title: message.title || '', text: message.text || '' }); return out; }
  if (type === 'integrations-strip') { const out=[{ kind: 'heading', text: rows.heading || '' }]; (rows.nodes || []).forEach((node,index)=>{ if (node.id && node.label) out.push({ kind:'node', id: node.id, label: node.label, order: index + 1 }); }); return out; }
  if (type === 'cards') { const cards = rows.map((i) => {
    const raw = objectRaw(i.raw);
    const target = i.target_type || raw.target_type || (i.url ? (String(i.url).startsWith('http') ? 'external' : 'legacy') : 'legacy');
    const card = { target_type: target };
    if (target === 'page') setClean(card, 'target_page_id', i.target_page_id || raw.target_page_id || '');
    else setClean(card, 'href', i.url || raw.href || raw.url || '');
    setClean(card, 'title', i.title);
    setClean(card, 'text', i.text);
    setClean(card, 'linkLabel', i.linkLabel);
    setClean(card, 'badge', coerceOrder('badge', i.order, raw.badge || raw.order));
    return card;
  }).filter((i) => i.title || i.text || i.href || i.target_page_id); const actionRows = rows.action || {}; let action = null; if (actionRows.enabled) { action = { target_type: actionRows.target_type || 'legacy', label: actionRows.label || '' }; if (action.target_type === 'page') action.target_page_id = actionRows.target_page_id || ''; else action.href = actionRows.href || ''; } return [{ version: 2, variant: 'default', cards, action }]; }
  if (type === 'cta') {
    const raw = objectRaw(first);
    setClean(raw, 'label', rows.label || '');
    setClean(raw, 'url', rows.url || '');
    setClean(raw, 'secondaryLabel', rows.secondaryLabel || '');
    setClean(raw, 'secondaryUrl', rows.secondaryUrl || '');
    setClean(raw, 'eyebrow', rows.eyebrow || '');
    if ('ctaMode' in rows || 'ctaMode' in raw) raw.ctaMode = ['global','custom','hidden'].includes(String(rows.ctaMode || raw.ctaMode || '')) ? String(rows.ctaMode || raw.ctaMode) : 'global';
    return Object.keys(raw).length ? [raw] : [];
  }
  if (type === 'image-text') {
    const raw = objectRaw(first);
    setClean(raw, 'image', rows.image || '');
    setClean(raw, 'alt', rows.alt || '');
    setClean(raw, 'position', rows.position || 'right');
    return Object.keys(raw).length ? [raw] : [];
  }
  if (type === 'video') return [serializeVideoEditorValues(rows)];
  if (type === 'ai-preview') return rows.map((i) => {
    const raw = objectRaw(i.raw);
    setClean(raw, 'kind', aiPreviewKind({ kind: i.kind }));
    const titleKey = ('text' in raw && !('title' in raw)) ? 'text' : ('label' in raw && !('title' in raw) ? 'label' : 'title');
    setClean(raw, titleKey, i.title);
    setClean(raw, 'detail', i.detail);
    setClean(raw, 'value', i.value);
    const hrefKey = ('url' in raw && !('href' in raw)) ? 'url' : 'href';
    setClean(raw, hrefKey, i.href);
    setClean(raw, 'order', coerceOrder('order', i.order, raw.order));
    return raw;
  }).filter((i) => i.title || i.text || i.label);
  if (type === 'network-visual') {
    const validation = validateNetworkVisualConfig(rows);
    if (!validation.ok || validation.warnings.length) throw new Error([...validation.errors, ...validation.warnings].join(' '));
    return [validation.config];
  }
  if (type === 'faq') return rows.map((i) => {
    const raw = objectRaw(i.raw);
    setClean(raw, 'question', i.title);
    setClean(raw, 'answer', i.text);
    return raw;
  }).filter((i) => i.question || i.answer);
  if (type === 'raw') {
    const parsed = JSON.parse(rawItemsText || '[]');
    if (!Array.isArray(parsed)) throw new Error('items JSON must be an array');
    return parsed;
  }
  return [];
}


const moveGapError = 'Nincs elegendő sorrendi hely a blokkok között. A blokksorrend technikai újrarendezése szükséges.';

export function sortOrderForMovedBlock(entries = [], movedIndex = -1) {
  const list = entries.map((entry, index) => ({ ...entry, index, sortOrder: Number(entry.sortOrder) }));
  const moved = list[movedIndex];
  if (!moved || moved.fixed) throw new Error(moveGapError);
  const previous = list[movedIndex - 1];
  const next = list[movedIndex + 1];
  const previousOrder = previous ? Number(previous.sortOrder) : Number.NEGATIVE_INFINITY;
  const nextOrder = next ? Number(next.sortOrder) : Number.POSITIVE_INFINITY;
  let sortOrder;
  if (Number.isFinite(previousOrder) && Number.isFinite(nextOrder)) {
    sortOrder = Math.floor((previousOrder + nextOrder) / 2);
    if (!(sortOrder > previousOrder && sortOrder < nextOrder)) throw new Error(moveGapError);
  } else if (Number.isFinite(previousOrder)) {
    sortOrder = previousOrder + 10;
  } else if (Number.isFinite(nextOrder)) {
    sortOrder = nextOrder - 10;
  } else {
    sortOrder = moved.sortOrder;
  }
  return sortOrder;
}

export function movedBlockOrder(entries = [], fromIndex = -1, direction = 'down') {
  const list = entries.map((entry, index) => ({ ...entry, index, sortOrder: Number(entry.sortOrder) }));
  const toIndex = direction === 'up' ? fromIndex - 1 : fromIndex + 1;
  const moved = list[fromIndex];
  const target = list[toIndex];
  if (!moved || !target || moved.fixed || target.fixed) throw new Error(moveGapError);
  const domOrder = list.slice();
  domOrder.splice(fromIndex, 1);
  domOrder.splice(toIndex, 0, moved);
  const movedIndex = domOrder.indexOf(moved);
  return { domOrder, moved, sortOrder: sortOrderForMovedBlock(domOrder, movedIndex), movedIndex };
}



export function duplicateItemRow(row) {
  if (!row?.cloneNode) return null;
  const clone = row.cloneNode(true);
  const sourceFields = [...row.querySelectorAll('input,textarea,select')];
  const cloneFields = [...clone.querySelectorAll('input,textarea,select')];
  sourceFields.forEach((source, index) => {
    const target = cloneFields[index];
    if (!target) return;
    if (source.type === 'checkbox' || source.type === 'radio') target.checked = source.checked;
    else target.value = source.value;
    if (target.tagName === 'TEXTAREA') target.textContent = source.value;
    if (target.tagName === 'SELECT') [...target.options].forEach((option) => { option.selected = option.value === source.value; });
  });
  row.after(clone);
  return clone;
}

